import React, { useState, useRef } from 'react';
import axios from 'axios';
import { 
  Box, 
  Button, 
  Card, 
  CardContent, 
  CircularProgress, 
  Container, 
  Grid, 
  Paper, 
  Typography,
  Alert,
  Divider,
  Chip,
  Stepper,
  Step,
  StepLabel,
  LinearProgress,
  Tooltip
} from '@mui/material';
import CameraAltIcon from '@mui/icons-material/CameraAlt';
import UploadFileIcon from '@mui/icons-material/UploadFile';
import DocumentScannerIcon from '@mui/icons-material/DocumentScanner';
import RestartAltIcon from '@mui/icons-material/RestartAlt';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import ErrorIcon from '@mui/icons-material/Error';
import HelpOutlineIcon from '@mui/icons-material/HelpOutline';

const Scanner = () => {
  const [selectedFile, setSelectedFile] = useState(null);
  const [previewUrl, setPreviewUrl] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [scanResult, setScanResult] = useState(null);
  const [scanProgress, setScanProgress] = useState(0);
  const [activeStep, setActiveStep] = useState(0);
  const [processingStep, setProcessingStep] = useState('');
  const fileInputRef = useRef(null);
  const videoRef = useRef(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const streamRef = useRef(null);

  // Define the scanning process steps
  const steps = [
    'Select or capture document',
    'Process image',
    'Extract information'
  ];

  const handleFileChange = (event) => {
    const file = event.target.files[0];
    if (file) {
      // Check if file is an image
      if (!file.type.startsWith('image/')) {
        setError('Please select an image file (JPEG, PNG, etc.)');
        return;
      }

      setSelectedFile(file);
      setPreviewUrl(URL.createObjectURL(file));
      setError(null);
      setActiveStep(1); // Move to step 2 (Process image)
      setScanResult(null); // Reset previous scan results
    }
  };

  const handleDrop = (event) => {
    event.preventDefault();
    const file = event.dataTransfer.files[0];
    if (file) {
      // Check if file is an image
      if (!file.type.startsWith('image/')) {
        setError('Please select an image file (JPEG, PNG, etc.)');
        return;
      }

      setSelectedFile(file);
      setPreviewUrl(URL.createObjectURL(file));
      setError(null);
      setActiveStep(1); // Move to step 2 (Process image)
      setScanResult(null); // Reset previous scan results
    }
  };

  const handleDragOver = (event) => {
    event.preventDefault();
  };

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      videoRef.current.srcObject = stream;
      streamRef.current = stream;
      setIsCameraActive(true);
      setError(null);
    } catch (err) {
      setError('Failed to access camera: ' + err.message);
    }
  };

  const stopCamera = () => {
    if (streamRef.current) {
      const tracks = streamRef.current.getTracks();
      tracks.forEach(track => track.stop());
      streamRef.current = null;
      setIsCameraActive(false);
    }
  };

  const captureImage = () => {
    if (videoRef.current) {
      const canvas = document.createElement('canvas');
      canvas.width = videoRef.current.videoWidth;
      canvas.height = videoRef.current.videoHeight;
      const ctx = canvas.getContext('2d');
      ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);

      canvas.toBlob((blob) => {
        const file = new File([blob], "capture.jpg", { type: "image/jpeg" });
        setSelectedFile(file);
        setPreviewUrl(URL.createObjectURL(file));
        stopCamera();
        setActiveStep(1); // Move to step 2 (Process image)
      }, 'image/jpeg');
    }
  };

  const handleScan = async () => {
    if (!selectedFile) {
      setError('Please select an image or capture one with the camera');
      return;
    }

    setLoading(true);
    setError(null);
    setActiveStep(1); // Move to processing step

    // Simulate progress for better UX
    setScanProgress(0);
    const progressInterval = setInterval(() => {
      setScanProgress(prev => {
        if (prev >= 90) {
          clearInterval(progressInterval);
          return 90;
        }
        return prev + 10;
      });
    }, 300);

    const formData = new FormData();
    formData.append('image', selectedFile);

    try {
      setProcessingStep('Preprocessing image...');

      // Make the API call
      const response = await axios.post('http://localhost:5001/api/scan', formData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      });

      setProcessingStep('Extracting document information...');
      setScanProgress(95);

      // Short delay for UX
      setTimeout(() => {
        setScanResult(response.data);
        setActiveStep(2); // Move to final step
        setScanProgress(100);
        setProcessingStep('Complete!');
      }, 500);

    } catch (err) {
      setError('Error scanning document: ' + (err.response?.data?.error || err.message));
      setActiveStep(0); // Go back to first step on error
    } finally {
      clearInterval(progressInterval);
      setLoading(false);
    }
  };

  const resetScan = () => {
    setSelectedFile(null);
    setPreviewUrl(null);
    setScanResult(null);
    setError(null);
    setScanProgress(0);
    setActiveStep(0);
    setProcessingStep('');
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  return (
    <Container maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
      <Typography variant="h4" gutterBottom>
        <DocumentScannerIcon sx={{ mr: 1, verticalAlign: 'middle' }} />
        Document Scanner
      </Typography>

      <Box sx={{ width: '100%', mb: 4 }}>
        <Stepper activeStep={activeStep} alternativeLabel>
          {steps.map((label) => (
            <Step key={label}>
              <StepLabel>{label}</StepLabel>
            </Step>
          ))}
        </Stepper>
      </Box>

      {error && (
        <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
          {error}
        </Alert>
      )}

      <Grid container spacing={3}>
        <Grid item xs={12} md={6}>
          <Paper
            sx={{
              p: 2,
              display: 'flex',
              flexDirection: 'column',
              minHeight: 400,
              position: 'relative',
              borderColor: previewUrl ? 'primary.main' : 'grey.300',
              borderWidth: previewUrl ? 2 : 1,
              borderStyle: 'solid',
            }}
            onDrop={handleDrop}
            onDragOver={handleDragOver}
          >
            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1 }}>
              <Typography variant="h6" gutterBottom>
                Upload or Capture Document
              </Typography>
              <Tooltip title="Supported documents: passports, ID cards, driver's licenses. For best results, ensure good lighting and that the document is fully visible.">
                <HelpOutlineIcon color="primary" />
              </Tooltip>
            </Box>

            {loading && (
              <Box sx={{ width: '100%', position: 'absolute', top: 0, left: 0, right: 0 }}>
                <LinearProgress variant="determinate" value={scanProgress} />
                {processingStep && (
                  <Typography variant="caption" color="text.secondary" sx={{ pl: 2 }}>
                    {processingStep}
                  </Typography>
                )}
              </Box>
            )}

            {isCameraActive ? (
              <Box sx={{ mt: 2, textAlign: 'center' }}>
                <video 
                  ref={videoRef} 
                  autoPlay 
                  style={{ width: '100%', maxHeight: '300px', objectFit: 'contain', border: '1px solid #eee' }} 
                />
                <Button
                  variant="contained"
                  color="primary"
                  onClick={captureImage}
                  sx={{ mt: 1 }}
                >
                  Capture
                </Button>
              </Box>
            ) : previewUrl ? (
              <Box sx={{ mb: 2, textAlign: 'center', position: 'relative' }}>
                <img 
                  src={previewUrl} 
                  alt="Document Preview" 
                  style={{ maxWidth: '100%', maxHeight: '300px', objectFit: 'contain', border: '1px solid #eee' }} 
                />
                <Chip 
                  label="Document Selected" 
                  color="success" 
                  size="small" 
                  icon={<CheckCircleIcon />}
                  sx={{ position: 'absolute', top: 10, right: 10 }}
                />
              </Box>
            ) : (
              <Box 
                sx={{ 
                  display: 'flex', 
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'center',
                  border: '1px dashed #ccc',
                  borderRadius: 2,
                  p: 3,
                  mb: 2,
                  flexGrow: 1,
                  backgroundColor: 'rgba(0, 0, 0, 0.02)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    backgroundColor: 'rgba(0, 0, 0, 0.04)',
                    borderColor: 'primary.main',
                  }
                }}
              >
                <DocumentScannerIcon sx={{ fontSize: 60, color: 'text.secondary', mb: 2 }} />
                <Typography variant="body1" color="text.secondary" align="center" gutterBottom>
                  Drag and drop a document image here, or click the buttons below to upload or capture.
                </Typography>
                <Typography variant="caption" color="text.secondary" align="center">
                  Supported formats: JPEG, PNG, BMP, TIFF
                </Typography>
              </Box>
            )}

            <Box sx={{ display: 'flex', justifyContent: 'space-between', mt: 'auto', flexWrap: 'wrap', gap: 1 }}>
              <Button
                variant="contained"
                startIcon={<UploadFileIcon />}
                onClick={() => fileInputRef.current.click()}
                disabled={loading || isCameraActive}
                sx={{ minWidth: '120px' }}
              >
                Upload
              </Button>
              <input
                type="file"
                ref={fileInputRef}
                onChange={handleFileChange}
                style={{ display: 'none' }}
                accept="image/*"
              />

              {!isCameraActive ? (
                <Button
                  variant="contained"
                  color="secondary"
                  startIcon={<CameraAltIcon />}
                  onClick={startCamera}
                  disabled={loading}
                  sx={{ minWidth: '120px' }}
                >
                  Camera
                </Button>
              ) : (
                <Button
                  variant="contained"
                  color="error"
                  onClick={stopCamera}
                  sx={{ minWidth: '120px' }}
                >
                  Stop Camera
                </Button>
              )}

              <Button
                variant="contained"
                color="primary"
                onClick={handleScan}
                disabled={!selectedFile || loading || isCameraActive}
                sx={{ minWidth: '120px' }}
              >
                {loading ? 'Processing...' : 'Scan Document'}
              </Button>

              {(previewUrl || scanResult) && (
                <Button
                  variant="outlined"
                  color="error"
                  startIcon={<RestartAltIcon />}
                  onClick={resetScan}
                  disabled={loading}
                  sx={{ minWidth: '120px' }}
                >
                  Reset
                </Button>
              )}
            </Box>
          </Paper>
        </Grid>

        <Grid item xs={12} md={6}>
          <Paper sx={{ 
            p: 2, 
            display: 'flex', 
            flexDirection: 'column', 
            minHeight: 400,
            borderColor: scanResult ? 'success.main' : 'grey.300',
            borderWidth: scanResult ? 2 : 1,
            borderStyle: 'solid',
          }}>
            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1 }}>
              <Typography variant="h6" gutterBottom>
                Scan Results
              </Typography>
              {scanResult && (
                <Chip 
                  label="Scan Complete" 
                  color="success" 
                  size="small" 
                  icon={<CheckCircleIcon />}
                />
              )}
            </Box>

            {scanResult ? (
              <Box>
                <Card variant="outlined" sx={{ mb: 2 }}>
                  <CardContent>
                    <Typography variant="h6" color="primary" gutterBottom>
                      Document Type: {scanResult.document_type.toUpperCase()}
                    </Typography>
                    <Typography variant="body1" gutterBottom>
                      Nationality: {scanResult.nationality}
                    </Typography>
                  </CardContent>
                </Card>

                <Typography variant="subtitle1" gutterBottom>
                  Extracted Information:
                </Typography>

                <Card variant="outlined" sx={{ mb: 2 }}>
                  <CardContent>
                    {scanResult.extracted_info.full_name && (
                      <Typography variant="body1" gutterBottom>
                        <strong>Full Name:</strong> {scanResult.extracted_info.full_name}
                      </Typography>
                    )}

                    {scanResult.extracted_info.document_number && (
                      <Typography variant="body1" gutterBottom>
                        <strong>Document Number:</strong> {scanResult.extracted_info.document_number}
                      </Typography>
                    )}

                    {scanResult.extracted_info.date_of_birth && (
                      <Typography variant="body1" gutterBottom>
                        <strong>Date of Birth:</strong> {scanResult.extracted_info.date_of_birth}
                      </Typography>
                    )}

                    {scanResult.extracted_info.date_of_expiry && (
                      <Typography variant="body1" gutterBottom>
                        <strong>Date of Expiry:</strong> {scanResult.extracted_info.date_of_expiry}
                      </Typography>
                    )}

                    {scanResult.extracted_info.gender && (
                      <Typography variant="body1" gutterBottom>
                        <strong>Gender:</strong> {scanResult.extracted_info.gender}
                      </Typography>
                    )}
                  </CardContent>
                </Card>

                {scanResult.extracted_info.mrz_data && (
                  <>
                    <Typography variant="subtitle1" gutterBottom>
                      MRZ Data:
                    </Typography>
                    <Card variant="outlined">
                      <CardContent>
                        <pre style={{ whiteSpace: 'pre-wrap', fontSize: '0.875rem' }}>
                          {JSON.stringify(scanResult.extracted_info.mrz_data, null, 2)}
                        </pre>
                      </CardContent>
                    </Card>
                  </>
                )}
              </Box>
            ) : (
              <Box 
                sx={{ 
                  display: 'flex', 
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'center',
                  border: '1px dashed #ccc',
                  borderRadius: 2,
                  p: 3,
                  flexGrow: 1
                }}
              >
                <DocumentScannerIcon sx={{ fontSize: 60, color: 'text.secondary', mb: 2, opacity: 0.5 }} />
                <Typography variant="body1" color="text.secondary" align="center">
                  No scan results yet. Upload or capture a document image and click "Scan Document".
                </Typography>
              </Box>
            )}
          </Paper>
        </Grid>
      </Grid>
    </Container>
  );
};

export default Scanner;
